import { BiquadEffect, calcHighShelfCoeffs, calcPeakingCoeffs } from "./BiquadEffect.js";
import { userToGainDb } from "./utils.js";

export class TrebleEffect extends BiquadEffect {
  private _normalized: number;
  private _sampleRate: number;

  constructor(channels: number, sampleRate: number, normalized: number) {
    super(
      "treble",
      () => {
        const gainDb = userToGainDb(this._normalized, 12);
        const shelf = calcHighShelfCoeffs(8000, this._sampleRate, gainDb, 0.7);
        let peak = null;
        if (gainDb > 3) {
          peak = calcPeakingCoeffs(12000, this._sampleRate, gainDb * 0.3, 1.2);
        }
        return { shelf, peak };
      },
      () => Math.abs(this._normalized) > 0.001,
      channels,
    );
    this._sampleRate = sampleRate;
    this._normalized = normalized;
  }

  get value(): number {
    return this._normalized;
  }

  setTreble(v: number): void {
    this._normalized = v;
    this.invalidate();
  }
}
